import { Question } from './questions';

const rawACTScience = [
  { id: 1, question: "A student measures the pH of four solutions. Solution 1: pH 3; Solution 2: pH 7; Solution 3: pH 10; Solution 4: pH 1. Which solution is the strongest acid?", choices: ["Solution 1", "Solution 2", "Solution 3", "Solution 4"], answer: "D", explanation: "Lower pH indicates stronger acidity; pH 1 is the lowest, so Solution 4 is the strongest acid." },
  { id: 2, question: "In an experiment, plants grown under red light had an average height of 15 cm, while those under blue light averaged 22 cm. What can be concluded?", choices: ["Red light inhibits growth more than blue light", "Blue light promotes growth more than red light", "Light color has no effect on height", "Plants need both colors equally"], answer: "B", explanation: "The higher average height under blue light suggests blue promotes growth more effectively than red." },
  { id: 3, question: "A graph shows reaction rate vs. temperature for an enzyme. The rate peaks at 37°C and drops sharply above 50°C. This indicates the enzyme is likely:", choices: ["Denatured at high temperatures", "Optimal at low temperatures", "Unaffected by temperature", "From a thermophilic organism"], answer: "A", explanation: "Enzymes denature (lose shape/function) at high temperatures, causing the sharp drop after the optimum." },
  { id: 4, question: "Table shows solubility of salt (g/100 mL water) at different temperatures: 0°C: 35g; 20°C: 36g; 50°C: 38g; 100°C: 40g. Solubility increases with temperature by approximately:", choices: ["0.05 g/°C", "0.5 g/°C", "5 g/°C", "50 g/°C"], answer: "A", explanation: "From 0°C to 100°C, increase of 5g over 100°C = 0.05 g/°C average." },
  { id: 5, question: "Scientist 1 claims craters on Europa are erased by sublimation of ice. Scientist 2 claims cryovolcanism fills them. Which supports Scientist 1?", choices: ["Presence of sulfur compounds", "Surface temperature allows ice to turn directly to gas", "Evidence of liquid water plumes", "High seismic activity"], answer: "B", explanation: "Sublimation (solid to gas) requires conditions where ice vaporizes, erasing features without melting." },
  { id: 6, question: "In a pendulum experiment, length is doubled while mass stays constant. Period (time per swing) should:", choices: ["Double", "Increase by √2", "Halve", "Remain the same"], answer: "B", explanation: "Period T ∝ √L, so doubling L multiplies T by √2 ≈ 1.41." },
  { id: 7, question: "Data: Enzyme activity at pH 4: 10%; pH 6: 60%; pH 7: 100%; pH 8: 70%; pH 10: 5%. Optimal pH is closest to:", choices: ["4", "6", "7", "10"], answer: "C", explanation: "Highest activity (100%) occurs at pH 7." },
  { id: 8, question: "A ball is dropped from 20 m. Ignoring air resistance, time to hit ground is approximately (g=10 m/s²):", choices: ["1 s", "2 s", "4 s", "20 s"], answer: "B", explanation: "s = ½gt² → 20 = 5t² → t² = 4 → t = 2 s." },
  { id: 9, question: "Two solutions: A has conductivity 5 mS/cm, B has 20 mS/cm. Which is likely more concentrated in ions?", choices: ["A", "B", "Equal", "Cannot determine"], answer: "B", explanation: "Higher conductivity indicates more ions available to carry current." },
  { id: 10, question: "In conflicting viewpoints, Scientist A says global temperature rise is due to solar activity; Scientist B says greenhouse gases. Data showing CO₂ levels rising with temperature supports:", choices: ["Scientist A only", "Scientist B only", "Both", "Neither"], answer: "B", explanation: "Greenhouse gases (like CO₂) trap heat, linking rising CO₂ to temperature increase." },
  { id: 11, question: "A population of bacteria doubles every 20 minutes. Starting with 100, after 1 hour the population is:", choices: ["200", "400", "800", "1600"], answer: "C", explanation: "3 doublings in 60 min (60/20=3) → 100 × 2³ = 800." },
  { id: 12, question: "Graph of velocity vs. time shows a straight line with positive slope. This indicates:", choices: ["Constant velocity", "Constant acceleration", "Deceleration", "Zero net force"], answer: "B", explanation: "Linear v-t graph means constant acceleration (slope = a)." },
  { id: 13, question: "In a food web, removing apex predators causes:", choices: ["Increase in primary producers", "Increase in herbivores", "Decrease in herbivores", "No change"], answer: "B", explanation: "Fewer predators allow herbivore populations to grow." },
  { id: 14, question: "Melting point data: Substance X: -10°C; Y: 150°C; Z: 800°C. Which is most likely ionic?", choices: ["X", "Y", "Z", "All covalent"], answer: "C", explanation: "Ionic compounds generally have high melting points due to strong electrostatic forces." },
  { id: 15, question: "Experiment: Plants in Group 1 get fertilizer A, Group 2 get fertilizer B, Group 3 none. Group 1 grows tallest. Conclusion:", choices: ["Fertilizer A is best", "Fertilizer B is worst", "No fertilizer is better", "Results inconclusive without controls for light/water"], answer: "A", explanation: "Assuming other variables controlled, A produces tallest plants." },
  { id: 16, question: "Density of object = 2.5 g/cm³, volume = 40 cm³. Mass is:", choices: ["10 g", "62.5 g", "100 g", "1000 g"], answer: "C", explanation: "m = d × V = 2.5 × 40 = 100 g." },
  { id: 17, question: "In osmosis, water moves from:", choices: ["High solute to low solute", "Low solute to high solute", "Equal concentrations", "High water to low water potential"], answer: "B", explanation: "Water moves toward higher solute concentration (lower water potential)." },
  { id: 18, question: "Table: Current (A) vs. Resistance (Ω): 10Ω: 1.2A; 20Ω: 0.6A; 40Ω: 0.3A. Voltage is constant at approximately:", choices: ["6 V", "12 V", "24 V", "120 V"], answer: "B", explanation: "V = I × R; consistent ~12 V (1.2×10=12, 0.6×20=12, etc.)." },
  { id: 19, question: "Fossils of marine organisms found on mountaintop suggest:", choices: ["Ancient sea level was higher", "Plate tectonics uplifted seabed", "Organisms flew there", "Flood deposited them"], answer: "B", explanation: "Uplift from tectonic forces explains marine fossils at elevation." },
  { id: 20, question: "A catalyst in a reaction:", choices: ["Increases activation energy", "Is consumed", "Lowers activation energy", "Changes equilibrium position"], answer: "C", explanation: "Catalysts speed reactions by lowering Ea without being used up." },
  { id: 21, question: "In a photoelectric effect experiment, increasing light intensity increases:", choices: ["Kinetic energy of electrons", "Number of ejected electrons", "Stopping voltage", "Threshold frequency"], answer: "B", explanation: "Intensity affects number of photons, thus number of electrons ejected." },
  { id: 22, question: "Data shows heart rate increases linearly with exercise intensity up to a point, then plateaus. This plateau indicates:", choices: ["Maximum heart rate reached", "Fatigue", "Oxygen debt", "Anaerobic threshold"], answer: "A", explanation: "Heart reaches its physiological maximum." },
  { id: 23, question: "Two gases at same T and V: Gas A has higher pressure. Gas A has:", choices: ["More molecules", "Fewer molecules", "Larger molecules", "Stronger intermolecular forces"], answer: "A", explanation: "From PV = nRT, higher P at same T/V means higher n." },
  { id: 24, question: "In gel electrophoresis, DNA fragments move toward the positive electrode because DNA is:", choices: ["Positively charged", "Negatively charged", "Neutral", "Hydrophobic"], answer: "B", explanation: "DNA has phosphate backbone, negatively charged." },
  { id: 25, question: "A circuit has resistors in parallel. Total resistance is:", choices: ["Sum of individual resistances", "Less than smallest individual", "Greater than largest individual", "Equal to average"], answer: "B", explanation: "Parallel: 1/R_total = sum 1/R_i, so R_total < smallest R." },
  { id: 26, question: "Scientist 1: Hurricanes fueled by warm ocean water. Scientist 2: Hurricanes caused by wind shear. Data showing stronger storms over warmer water supports:", choices: ["Scientist 1", "Scientist 2", "Both", "Neither"], answer: "A", explanation: "Warm water provides energy via evaporation." },
  { id: 27, question: "pH change from 3 to 4 means [H⁺] decreases by factor of:", choices: ["1", "10", "100", "1000"], answer: "B", explanation: "Each pH unit change = 10× change in [H⁺]." },
  { id: 28, question: "In natural selection, variation arises primarily from:", choices: ["Mutation", "Migration", "Genetic drift", "All equally"], answer: "A", explanation: "Mutations create new alleles for selection to act on." },
  { id: 29, question: "Wave speed in medium increases when:", choices: ["Frequency increases", "Wavelength decreases", "Medium stiffness increases", "Amplitude increases"], answer: "C", explanation: "v = √(stiffness/density) for mechanical waves." },
  { id: 30, question: "Enzyme rate vs. substrate concentration graph is hyperbolic because:", choices: ["All active sites eventually saturated", "Reaction becomes zero-order", "Both A and B", "Substrate inhibits enzyme"], answer: "C", explanation: "Michaelis-Menten kinetics: rate approaches Vmax as sites fill." },
  { id: 31, question: "Object falls freely. Its acceleration:", choices: ["Increases", "Decreases", "Constant 9.8 m/s²", "Zero after 1 s"], answer: "C", explanation: "g is constant near Earth's surface (ignoring air)." },
  { id: 32, question: "In pedigree, trait skips generations and appears more in males. Likely:", choices: ["Autosomal dominant", "X-linked recessive", "Autosomal recessive", "Y-linked"], answer: "B", explanation: "X-linked recessive: females carriers, males express if inherited." },
  { id: 33, question: "Boiling point elevation is greatest in solution with:", choices: ["Glucose 0.1 M", "NaCl 0.1 M", "CaCl₂ 0.1 M", "Sucrose 0.1 M"], answer: "C", explanation: "Colligative property depends on particles; CaCl₂ → 3 ions." },
  { id: 34, question: "Data: Light intensity vs. distance from source: 1 m: 100 units; 2 m: 25 units; 4 m: 6.25 units. Follows:", choices: ["Inverse square law", "Linear decrease", "Exponential decay", "Constant"], answer: "A", explanation: "Intensity ∝ 1/d² (100→25=1/4 when d doubles)." },
  { id: 35, question: "In conflicting views on plate movement: Scientist 1 says convection currents; Scientist 2 says slab pull. Evidence of deep subduction supports:", choices: ["Scientist 1 only", "Scientist 2 only", "Both", "Neither"], answer: "B", explanation: "Slab pull: dense subducting plate pulls lithosphere." },
  { id: 36, question: "Mitosis produces:", choices: ["2 identical diploid cells", "4 haploid cells", "2 haploid cells", "Genetically diverse cells"], answer: "A", explanation: "Mitosis maintains chromosome number for growth/repair." },
  { id: 37, question: "Gas volume at constant P and T is proportional to:", choices: ["Moles", "Pressure", "Temperature", "Density"], answer: "A", explanation: "Avogadro's law: V ∝ n." },
  { id: 38, question: "In a food chain, energy transfer efficiency between trophic levels is typically:", choices: ["100%", "50%", "10%", "1%"], answer: "C", explanation: "≈10% rule due to heat loss." },
  { id: 39, question: "Refraction occurs because light changes:", choices: ["Speed in different media", "Frequency", "Color", "Polarization"], answer: "A", explanation: "Speed change bends ray (Snell's law)." },
  { id: 40, question: "Biodiversity is highest in:", choices: ["Tundra", "Desert", "Tropical rainforest", "Temperate forest"], answer: "C", explanation: "Stable climate, high energy input support more species." },
  { id: 41, question: "Half-life of isotope is 10 years. After 30 years, fraction remaining:", choices: ["1/2", "1/4", "1/8", "1/16"], answer: "C", explanation: "3 half-lives → (1/2)³ = 1/8." },
  { id: 42, question: "In series circuit, current is:", choices: ["Same everywhere", "Different at each resistor", "Zero at branches", "Inversely proportional to voltage"], answer: "A", explanation: "Single path, current constant." },
  { id: 43, question: "Photosynthesis rate increases with CO₂ concentration until:", choices: ["Light saturation", "Enzyme saturation", "Temperature optimum", "Water limitation"], answer: "B", explanation: "CO₂ becomes saturating when Calvin cycle enzymes maxed." },
  { id: 44, question: "Object in circular motion has constant:", choices: ["Speed", "Velocity", "Acceleration magnitude and direction", "Both A and C"], answer: "A", explanation: "Speed constant, but velocity changes direction → centripetal acceleration." },
  { id: 45, question: "Hard water contains high levels of:", choices: ["Na⁺", "Ca²⁺ and Mg²⁺", "K⁺", "Cl⁻"], answer: "B", explanation: "Causes scaling due to Ca/Mg ions." },
  { id: 46, question: "Ecological succession begins with:", choices: ["Climax community", "Pioneer species", "Keystone species", "Apex predators"], answer: "B", explanation: "Pioneers colonize bare area first." },
  { id: 47, question: "In electromagnetic spectrum, higher frequency corresponds to:", choices: ["Longer wavelength", "Lower energy", "Higher energy", "Radio waves"], answer: "C", explanation: "E = h f, energy proportional to frequency." },
  { id: 48, question: "Allele frequency change due to chance is:", choices: ["Natural selection", "Genetic drift", "Gene flow", "Mutation"], answer: "B", explanation: "Random shifts in small populations." },
  { id: 49, question: "Acid rain is primarily caused by emissions of:", choices: ["CO₂ and CH₄", "SO₂ and NOₓ", "O₃ and VOCs", "Particulates"], answer: "B", explanation: "Form H₂SO₄ and HNO₃ in atmosphere." },
  { id: 50, question: "In lever systems, mechanical advantage is highest when:", choices: ["Effort arm is longest", "Load arm is longest", "Fulcrum is at end", "Arms equal"], answer: "A", explanation: "MA = effort arm / load arm; longer effort arm increases MA." },
  { id: 51, question: "A student records the mass of a solution before and after adding a metal. Mass increases by 0.5 g. This is most likely because:", choices: ["The metal reacted and produced a gas that escaped", "Water evaporated during the reaction", "The metal dissolved and displaced solution volume", "A precipitate formed and was included in the final mass"], answer: "D", explanation: "If mass increases, a solid precipitate likely formed and remained in the container, adding to the total measured mass." },
  { id: 52, question: "In a study, fish exposed to 0.1 ppm mercury grew 15% slower than controls. At 0.01 ppm, growth was only 2% slower. This suggests mercury toxicity is:", choices: ["Threshold-based", "Linear", "Exponential", "Independent of concentration"], answer: "A", explanation: "The much larger effect at higher concentration and small effect at low concentration indicates a threshold below which effects are minimal." },
  { id: 53, question: "A circuit contains three identical resistors in series. Total resistance is 30 Ω. If one resistor is removed, total resistance becomes:", choices: ["10 Ω", "15 Ω", "20 Ω", "30 Ω"], answer: "C", explanation: "Each resistor = 10 Ω. Removing one leaves two in series → 20 Ω." },
  { id: 54, question: "Table: Distance from light source (cm) vs. Illuminance (lux): 10 cm: 900; 20 cm: 225; 40 cm: 56.25. This relationship follows:", choices: ["Inverse linear", "Inverse square", "Direct square", "Exponential decay"], answer: "B", explanation: "Illuminance decreases with the square of distance (900 → 225 = 1/4 when distance doubles)." },
  { id: 55, question: "Scientist 1: Dinosaurs went extinct due to asteroid impact. Scientist 2: Due to massive volcanism. Evidence of shocked quartz and iridium layer supports:", choices: ["Scientist 1", "Scientist 2", "Both", "Neither"], answer: "A", explanation: "Shocked quartz and global iridium spike are characteristic of a large impact event." },
  { id: 56, question: "A student measures the time for a ball to roll down ramps of different lengths but same height. Time is longest for:", choices: ["Steepest ramp", "Longest ramp", "Shortest ramp", "All the same"], answer: "B", explanation: "Longer ramp means gentler slope → lower acceleration → longer time, even though final speed is the same." },
  { id: 57, question: "In a population, allele A frequency = 0.7, allele a = 0.3. Expected frequency of heterozygotes (Aa) under Hardy-Weinberg equilibrium is:", choices: ["0.21", "0.42", "0.49", "0.70"], answer: "B", explanation: "2pq = 2 × 0.7 × 0.3 = 0.42." },
  { id: 58, question: "Graph shows dissolved oxygen in water vs. temperature. As temperature increases, dissolved oxygen:", choices: ["Increases linearly", "Decreases", "Remains constant", "Increases exponentially"], answer: "B", explanation: "Gases are less soluble in warmer water; dissolved O₂ decreases with rising temperature." },
  { id: 59, question: "A student mixes equal volumes of 0.1 M HCl and 0.1 M NaOH. The resulting solution is:", choices: ["Strongly acidic", "Neutral", "Weakly basic", "Weakly acidic"], answer: "B", explanation: "Strong acid + strong base in equal concentrations → complete neutralization → pH 7." },
  { id: 60, question: "In a double-slit experiment, increasing the distance between slits causes the interference pattern to:", choices: ["Spread out more", "Become more compressed", "Disappear", "Remain unchanged"], answer: "B", explanation: "Larger slit separation decreases fringe spacing (fringe width ∝ 1/d)." },
  { id: 61, question: "Data: Plant growth (cm) with different fertilizers: Control: 8 cm; N only: 14 cm; P only: 9 cm; N+P: 22 cm. This demonstrates:", choices: ["Nitrogen is limiting", "Synergistic effect of N and P", "Phosphorus toxicity", "No effect of nutrients"], answer: "B", explanation: "Combined N+P produces much more growth than either alone → synergy." },
  { id: 62, question: "A wave has frequency 4 Hz and wavelength 2 m. Its speed is:", choices: ["0.5 m/s", "2 m/s", "8 m/s", "16 m/s"], answer: "C", explanation: "v = f × λ = 4 × 2 = 8 m/s." },
  { id: 63, question: "In an ecosystem, 10,000 kJ of energy enters at the producer level. Approximately how much energy is available to tertiary consumers?", choices: ["100 kJ", "10 kJ", "1 kJ", "0.1 kJ"], answer: "B", explanation: "10% rule: 10,000 → 1,000 (herbivores) → 100 (secondary) → 10 (tertiary)." },
  { id: 64, question: "A student heats a gas in a sealed container. Pressure increases because:", choices: ["Volume increases", "Molecules move faster and collide more frequently", "Number of molecules increases", "Mass of gas increases"], answer: "B", explanation: "At constant volume, higher temperature increases kinetic energy → more forceful collisions → higher pressure." },
  { id: 65, question: "Fossil evidence shows transitional forms between fish and tetrapods. This supports:", choices: ["Gradual evolution", "Punctuated equilibrium", "Intelligent design", "Spontaneous generation"], answer: "A", explanation: "Transitional fossils indicate gradual change over time." },
  { id: 66, question: "In a titration, 25 mL of 0.2 M NaOH neutralizes 50 mL of HCl. Concentration of HCl is:", choices: ["0.1 M", "0.2 M", "0.4 M", "0.8 M"], answer: "A", explanation: "Moles NaOH = 0.025 × 0.2 = 0.005. Same moles HCl in 0.05 L → 0.005 / 0.05 = 0.1 M." },
  { id: 67, question: "A pendulum swings faster (shorter period) when:", choices: ["Mass is increased", "Length is decreased", "Amplitude is increased", "Gravity is decreased"], answer: "B", explanation: "T ∝ √L; shorter length → shorter period." },
  { id: 68, question: "Enzyme activity is highest at 40°C and drops to near zero at 70°C. This is most likely because:", choices: ["Substrate denatures", "Enzyme denatures", "pH changes", "Reaction becomes endothermic"], answer: "B", explanation: "Enzymes lose shape (denature) at high temperatures, losing catalytic ability." },
  { id: 69, question: "Scientist 1: Earth's core is solid iron. Scientist 2: Liquid iron outer core, solid inner core. Seismic data showing S-waves stop at the outer core supports:", choices: ["Scientist 1 only", "Scientist 2 only", "Both", "Neither"], answer: "B", explanation: "S-waves do not travel through liquids; their absence in the outer core indicates liquid." },
  { id: 70, question: "A car accelerates from 0 to 20 m/s in 5 s. Its acceleration is:", choices: ["2 m/s²", "4 m/s²", "10 m/s²", "100 m/s²"], answer: "B", explanation: "a = Δv / t = 20 / 5 = 4 m/s²." },
  { id: 71, question: "In gel electrophoresis, smaller DNA fragments travel:", choices: ["Farther", "Less far", "At the same rate as larger fragments", "Toward the negative electrode"], answer: "A", explanation: "Smaller fragments move faster through the gel matrix." },
  { id: 72, question: "Data shows coral bleaching increases sharply above 30°C water temperature. This is primarily due to:", choices: ["Loss of symbiotic algae", "Increased predation", "Decreased salinity", "Ocean acidification"], answer: "A", explanation: "High temperatures cause zooxanthellae to be expelled, leading to bleaching." },
  { id: 73, question: "A solution turns litmus paper red and reacts with magnesium to produce gas. It is most likely:", choices: ["NaOH", "HCl", "NaCl", "Sugar solution"], answer: "B", explanation: "Acids turn litmus red and react with metals to produce H₂ gas." },
  { id: 74, question: "In a food web, krill are eaten by penguins and whales. If krill are overharvested, which is most likely to decline first?", choices: ["Phytoplankton", "Penguins", "Whales", "Seals"], answer: "B", explanation: "Direct consumers of krill (penguins) will be affected before higher-level predators." },
  { id: 75, question: "Object A has mass 2 kg and velocity 5 m/s. Object B has mass 5 kg and velocity 2 m/s. Which has greater momentum?", choices: ["Object A", "Object B", "Equal", "Cannot determine"], answer: "C", explanation: "p = m × v; A: 2 × 5 = 10 kg·m/s; B: 5 × 2 = 10 kg·m/s → equal momentum." },
  { id: 76, question: "A student measures reaction rate at different temperatures. Rate doubles every 10°C increase. This is consistent with:", choices: ["Arrhenius equation", "Ideal gas law", "Boyle's law", "Le Chatelier's principle"], answer: "A", explanation: "Rate typically doubles every ~10°C rise due to increased collision energy/frequency (Arrhenius)." },
  { id: 77, question: "In meiosis, crossing over occurs during:", choices: ["Prophase I", "Metaphase II", "Anaphase I", "Telophase II"], answer: "A", explanation: "Crossing over (genetic recombination) happens in prophase I of meiosis." },
  { id: 78, question: "A rock sample contains 25% of its original radioactive isotope after 20 years. Half-life is approximately:", choices: ["5 years", "10 years", "20 years", "40 years"], answer: "B", explanation: "After 2 half-lives, 25% remains (½ × ½ = ¼). 2 half-lives = 20 years → half-life = 10 years." },
  { id: 79, question: "Scientist 1: Global warming is natural cycle. Scientist 2: Human CO₂ emissions are primary cause. Data showing unprecedented CO₂ levels in 800,000 years supports:", choices: ["Scientist 1", "Scientist 2", "Both", "Neither"], answer: "B", explanation: "Current CO₂ spike is far above natural historical variation." },
  { id: 80, question: "In a series circuit with two bulbs, one burns out. The other bulb:", choices: ["Stays the same brightness", "Gets brighter", "Goes out", "Flickers"], answer: "C", explanation: "Series circuit is broken when one component fails → current stops." },
  { id: 81, question: "A student observes that adding salt lowers the freezing point of water. This is an example of:", choices: ["Colligative property", "Chemical reaction", "Phase transition", "Specific heat change"], answer: "A", explanation: "Freezing point depression is a colligative property dependent on number of solute particles." },
  { id: 82, question: "Graph shows population growth rate vs. population density. Growth rate is highest at low density and becomes negative at high density. This is characteristic of:", choices: ["Logistic growth", "Exponential growth", "Linear growth", "Cyclic growth"], answer: "A", explanation: "Logistic model shows density-dependent regulation with carrying capacity." },
  { id: 83, question: "A ray of light enters water from air at 60° angle of incidence. The refracted angle will be:", choices: ["Greater than 60°", "Less than 60°", "Equal to 60°", "90°"], answer: "B", explanation: "Light bends toward the normal when entering a denser medium (n_water > n_air)." },
  { id: 84, question: "In a pedigree, a trait appears in every generation and both males and females are affected equally. Most likely inheritance pattern is:", choices: ["Autosomal dominant", "X-linked recessive", "Autosomal recessive", "Mitochondrial"], answer: "A", explanation: "Autosomal dominant traits appear in every generation and affect both sexes equally." },
  { id: 85, question: "A student measures the volume of gas produced when different masses of CaCO₃ react with excess HCl. Volume is directly proportional to mass of CaCO₃. This supports:", choices: ["Law of definite proportions", "Law of conservation of mass", "Avogadro's law", "Ideal gas law"], answer: "A", explanation: "Constant ratio of products to reactant mass supports definite proportions." },
  { id: 86, question: "In an experiment, heart rate increases most rapidly when subjects exercise at:", choices: ["30% max effort", "60% max effort", "90% max effort", "All intensities equally"], answer: "C", explanation: "Heart rate rises more steeply near maximum effort to meet oxygen demand." },
  { id: 87, question: "A force of 20 N is applied to a 5 kg object. Acceleration is:", choices: ["4 m/s²", "25 m/s²", "100 m/s²", "0.25 m/s²"], answer: "A", explanation: "F = m × a → a = F / m = 20 / 5 = 4 m/s²." },
  { id: 88, question: "Data shows bacterial growth is fastest at pH 7 and very slow at pH 4 and pH 10. These bacteria are best classified as:", choices: ["Acidophiles", "Alkaliphiles", "Neutrophiles", "Halophiles"], answer: "C", explanation: "Neutrophiles grow best near neutral pH (around 7)." },
  { id: 89, question: "In a transformer, if primary voltage is 120 V and secondary is 12 V, the turns ratio (primary:secondary) is:", choices: ["1:10", "10:1", "1:1", "12:120"], answer: "B", explanation: "V_p / V_s = N_p / N_s → 120 / 12 = 10 → 10:1." },
  { id: 90, question: "A student observes that plants in shaded areas have larger leaves than those in full sun. This is an example of:", choices: ["Phototropism", "Phenotypic plasticity", "Genetic drift", "Mutation"], answer: "B", explanation: "Same species, different environment → different phenotype (plasticity)." },
  { id: 91, question: "A sound wave has frequency 440 Hz. If the speed of sound is 340 m/s, wavelength is:", choices: ["0.77 m", "1.3 m", "340 m", "149,600 m"], answer: "A", explanation: "λ = v / f = 340 / 440 ≈ 0.77 m." },
  { id: 92, question: "Scientist 1: Tectonic plates move due to mantle convection. Scientist 2: Ridge push and slab pull are main drivers. Evidence of faster subduction zones moving faster supports:", choices: ["Scientist 1 only", "Scientist 2 only", "Both", "Neither"], answer: "B", explanation: "Slab pull is stronger in regions with active subduction." },
  { id: 93, question: "In an experiment, reaction rate increases when concentration of reactant is doubled. This indicates the reaction is:", choices: ["Zero-order", "First-order", "Second-order", "Cannot determine from information"], answer: "B", explanation: "First-order: rate ∝ [reactant]; doubling concentration doubles rate." },
  { id: 94, question: "A student measures conductivity of solutions. Highest conductivity is observed in:", choices: ["0.1 M sugar", "0.1 M acetic acid", "0.1 M NaCl", "Distilled water"], answer: "C", explanation: "Strong electrolyte (NaCl) fully dissociates → highest ion concentration → highest conductivity." },
  { id: 95, question: "In a population bottleneck, genetic diversity is most likely to:", choices: ["Increase", "Decrease", "Remain unchanged", "Become more homozygous"], answer: "B", explanation: "Small surviving population loses alleles due to genetic drift." },
  { id: 96, question: "A ball is thrown upward at 20 m/s. Time to reach maximum height (g = 10 m/s²) is:", choices: ["1 s", "2 s", "4 s", "20 s"], answer: "B", explanation: "v = u + at → 0 = 20 - 10t → t = 2 s." },
  { id: 97, question: "In photosynthesis, the light-dependent reactions produce:", choices: ["Glucose and oxygen", "ATP and NADPH", "CO₂ and water", "Chlorophyll and carotenoids"], answer: "B", explanation: "Light reactions generate ATP and NADPH for the Calvin cycle." },
  { id: 98, question: "A student finds that adding more catalyst increases reaction rate up to a point, then no further increase occurs. This is because:", choices: ["Catalyst is consumed", "All substrate is reacted", "Active sites are saturated", "Temperature changed"], answer: "C", explanation: "Catalyst amount can limit rate only until all substrate molecules can access active sites." },
  { id: 99, question: "Data shows earthquake frequency is highest near plate boundaries. This supports:", choices: ["Continental drift theory", "Plate tectonics theory", "Expanding Earth theory", "Static crust theory"], answer: "B", explanation: "Most earthquakes occur at plate boundaries due to movement and friction." },
  { id: 100, question: "In a reflex arc, the shortest pathway for a knee-jerk reflex involves:", choices: ["Sensory neuron → interneuron → motor neuron", "Sensory neuron → motor neuron", "Brain → spinal cord → muscle", "Muscle → brain → muscle"], answer: "B", explanation: "Monosynaptic reflex (knee-jerk) has direct sensory-to-motor connection in spinal cord." },
  { id: 101, question: "A student records the distance a toy car travels on different surfaces. Carpet: 1.2 m; Wood: 2.8 m; Tile: 4.1 m (same initial push). Which surface has the least friction?", choices: ["Carpet", "Wood", "Tile", "All equal"], answer: "C", explanation: "Longest distance means least energy lost to friction → Tile has the least friction." },
  { id: 102, question: "In a table of gas volumes at STP, 1 mole of each gas occupies approximately 22.4 L. This supports:", choices: ["Boyle's law", "Charles's law", "Avogadro's law", "Ideal gas law only"], answer: "C", explanation: "Avogadro's law states equal volumes of gases at same T and P contain equal numbers of molecules (1 mole = 22.4 L at STP)." },
  { id: 103, question: "Graph of absorbance vs. concentration for a colored solution is linear. This follows:", choices: ["Beer's law", "Henry's law", "Raoult's law", "Le Chatelier's principle"], answer: "A", explanation: "Beer's law: absorbance is directly proportional to concentration (A = εlc)." },
  { id: 104, question: "Scientist 1: Dinosaurs went extinct due to asteroid impact. Scientist 2: Due to massive volcanism. Evidence of iridium layer worldwide supports:", choices: ["Scientist 1", "Scientist 2", "Both", "Neither"], answer: "A", explanation: "Iridium is rare on Earth but common in asteroids; a global layer supports impact hypothesis." },
  { id: 105, question: "A student measures pulse rate before and after exercise: Rest: 68 bpm; After 2 min jogging: 124 bpm; After 5 min recovery: 82 bpm. The heart rate during recovery dropped by:", choices: ["42 bpm", "56 bpm", "14 bpm", "68 bpm"], answer: "A", explanation: "Recovery drop: 124 - 82 = 42 bpm over the 5 minute recovery period." },
  { id: 106, question: "In a pendulum experiment, increasing mass while keeping length constant causes the period to:", choices: ["Increase", "Decrease", "Remain the same", "Become zero"], answer: "C", explanation: "Period of a simple pendulum depends only on length and g, not mass." },
  { id: 107, question: "Table shows conductivity of solutions: Distilled water: 0.01 mS/cm; Tap water: 0.5 mS/cm; 0.1 M NaCl: 10 mS/cm; 0.1 M sugar: 0.02 mS/cm. Best conductor is:", choices: ["Distilled water", "Tap water", "0.1 M NaCl", "0.1 M sugar"], answer: "C", explanation: "NaCl fully dissociates into Na⁺ and Cl⁻ ions, producing the highest concentration of charge carriers and thus the highest conductivity (10 mS/cm)." },
  { id: 108, question: "Scientist 1: Earth's core is entirely solid iron. Scientist 2: Liquid iron outer core with solid inner core. Seismic data showing S-waves not passing through the outer core supports:", choices: ["Scientist 1", "Scientist 2", "Both", "Neither"], answer: "B", explanation: "S-waves (shear waves) cannot travel through liquids. Their absence in the outer core indicates it is liquid, supporting Scientist 2's model." },
  { id: 109, question: "A solution turns blue litmus red and reacts vigorously with magnesium to produce gas bubbles. It is most likely:", choices: ["Strong acid", "Weak acid", "Strong base", "Neutral salt"], answer: "A", explanation: "Turning litmus red indicates acid; vigorous reaction with Mg producing H₂ gas indicates a strong acid." },
  { id: 110, question: "Graph shows pressure vs. volume for a fixed amount of gas at constant temperature. The shape of the curve is:", choices: ["Straight line", "Hyperbola", "Parabola", "Exponential decay"], answer: "B", explanation: "Boyle's law: P × V = constant at fixed T. P vs V plots as a hyperbola (inverse relationship)." },
  { id: 111, question: "A car accelerates from 0 to 30 m/s in 6 seconds. Average acceleration is:", choices: ["5 m/s²", "180 m/s²", "0.2 m/s²", "30 m/s²"], answer: "A", explanation: "a = Δv / Δt = (30 - 0) / 6 = 5 m/s²." },
  { id: 112, question: "Hardness of water is primarily caused by dissolved:", choices: ["Na⁺ and Cl⁻", "Ca²⁺ and Mg²⁺", "K⁺ and SO₄²⁻", "HCO₃⁻ only"], answer: "B", explanation: "Water hardness is due to dissolved calcium and magnesium ions from minerals like limestone." },
  { id: 113, question: "In primary succession, the first organisms to colonize bare rock are typically:", choices: ["Lichens", "Trees", "Grasses", "Shrubs"], answer: "A", explanation: "Lichens are pioneer species that secrete acids to break down rock, creating soil precursors for later colonizers." },
  { id: 114, difficulty: 8, question: "Figure 1 shows reaction rate vs. substrate concentration for Enzyme X at two temperatures. At 25°C the curve plateaus at 80 units; at 37°C it plateaus at 120 units. If the experiment is repeated at 45°C, the most likely maximum rate is:", choices: ["<80 units", "80–120 units", ">120 units", "Cannot be determined from the data"], answer: "A", explanation: "At 45°C (above optimum for most enzymes), denaturation begins → maximum rate drops below the 37°C plateau and likely below 80 units." },
  { id: 115, difficulty: 9, question: "In Experiment 3, when inhibitor concentration is doubled, Km increases but Vmax remains unchanged. This pattern is characteristic of:", choices: ["Competitive inhibition", "Noncompetitive inhibition", "Uncompetitive inhibition", "Irreversible inhibition"], answer: "A", explanation: "Competitive inhibitors increase apparent Km but do not change Vmax — enough substrate overcomes the inhibition." },
  { id: 116, difficulty: 8, question: "Two scientists disagree about whether observed planetary temperature increase is caused by increased solar output or greenhouse gas accumulation. Data show solar output has been stable for 50 years while CO₂ levels and temperature both rose steadily. This evidence most strongly supports:", choices: ["Solar output hypothesis only", "Greenhouse gas hypothesis only", "Both hypotheses equally", "Neither hypothesis"], answer: "B", explanation: "Stable solar output eliminates it as the cause; concurrent CO₂ and temperature rise supports greenhouse mechanism." },
  { id: 117, difficulty: 9, question: "Figure 2 plots velocity of sound in air vs. temperature from 0°C to 100°C. The relationship is nearly linear with positive slope. If an additional trial were conducted at –50°C, the sound velocity would most likely be:", choices: ["Higher than at 0°C", "The same as at 0°C", "Lower than at 0°C", "Cannot be predicted"], answer: "C", explanation: "Sound velocity increases with temperature; extrapolating the linear trend backward gives lower velocity at –50°C." },
  { id: 118, difficulty: 10, question: "Table 1 shows percent survival of bacteria exposed to antibiotic A at various concentrations. At 2 μg/mL, survival drops from 95% to 5% between generations 1 and 5. At 8 μg/mL the drop occurs between generations 1 and 3. The most reasonable conclusion is:", choices: ["Higher concentrations select for resistance more rapidly", "Higher concentrations kill bacteria more slowly", "Resistance develops faster at lower concentrations", "The antibiotic is ineffective above 4 μg/mL"], answer: "A", explanation: "At higher concentration, the population crashes faster — stronger selection pressure means only highly resistant mutants survive, so resistant strain dominates more quickly." },
  { id: 119, difficulty: 8, question: "In a pendulum experiment, period vs. length is plotted on log-log paper and forms a straight line with slope ≈ 0.5. This supports the theoretical relationship T ∝:", choices: ["L", "√L", "L²", "1/√L"], answer: "B", explanation: "On log-log plot, slope = exponent in power law. T = 2π√(L/g) → T ∝ L^(1/2) → slope = 0.5." },
  { id: 120, difficulty: 9, question: "Figure 3 shows absorbance vs. wavelength for three solutions. Solution B has a peak at 520 nm while A and C peak at 450 nm and 620 nm. When equal volumes of A and C are mixed, the resulting solution most likely appears:", choices: ["Green", "Orange", "Purple", "Colorless"], answer: "C", explanation: "Absorbing at 450 nm (blue) and 620 nm (orange-red) means the mixture transmits/reflects purple/magenta." },
  { id: 121, difficulty: 10, question: "Scientist 1 argues recent coral bleaching is caused primarily by ocean warming. Scientist 2 argues it is caused primarily by local pollution/nutrient runoff. A study shows bleaching intensity correlates strongly with temperature anomalies but shows no significant correlation with measured nutrient levels. Which conclusion is best supported?", choices: ["Scientist 1 is correct and Scientist 2 is incorrect", "Scientist 2 is correct and Scientist 1 is incorrect", "Both mechanisms contribute equally", "Neither mechanism is supported"], answer: "A", explanation: "Strong correlation with temperature + no correlation with nutrients supports Scientist 1 and weakens Scientist 2's claim." },
  { id: 122, difficulty: 9, question: "A ball is thrown vertically upward. Figure 4 shows position vs. time (parabolic) and velocity vs. time (straight line with negative slope). The acceleration due to gravity is closest to:", choices: ["–5 m/s²", "–9.8 m/s²", "–15 m/s²", "Cannot be determined"], answer: "B", explanation: "Slope of v-t graph = acceleration. The standard value of g ≈ 9.8 m/s² matches the observed slope." },
  { id: 123, difficulty: 8, question: "In a dialysis tube experiment, starch solution inside turns blue-black with iodine after 30 min, but glucose solution inside shows no color change. This indicates the dialysis membrane is:", choices: ["Permeable to both starch and glucose", "Permeable to glucose but not starch", "Permeable to starch but not glucose", "Impermeable to both"], answer: "B", explanation: "Iodine diffused in (small molecule) and reacted with starch (stayed inside — too large to leave). Glucose diffused out through the membrane." },
  { id: 124, difficulty: 8, question: "Figure 1 shows population size of Species A over time in the presence and absence of Species B. When Species B is present, Species A grows more slowly and plateaus at a lower level. This pattern most strongly suggests that Species B is acting as a:", choices: ["Mutualist", "Predator", "Competitor", "Parasite"], answer: "C", explanation: "Lower carrying capacity and slower growth when B is present indicate resource competition." },
  { id: 125, difficulty: 9, question: "In a titration curve (pH vs. volume of base added), the equivalence point occurs at pH 8.7. The acid being titrated is most likely:", choices: ["Strong acid", "Weak acid with Ka ≈ 10⁻⁵", "Weak acid with Ka ≈ 10⁻⁹", "Polyprotic acid (second equivalence point)"], answer: "B", explanation: "For weak acid + strong base, equivalence pH >7. pH ≈ 8.7 suggests pKa ≈ 4–5 (Ka ≈ 10⁻⁵)." },
  { id: 126, difficulty: 10, question: "Scientist 1 claims dark matter explains flat galactic rotation curves. Scientist 2 claims modified Newtonian dynamics (MOND) explains the same data without dark matter. A study shows MOND accurately predicts rotation curves for spiral galaxies but fails for galaxy cluster dynamics and gravitational lensing. The data most strongly support:", choices: ["Scientist 1 only", "Scientist 2 only", "Both equally", "Neither"], answer: "A", explanation: "MOND's failure on larger scales weakens Scientist 2, while dark matter consistently explains all scales." },
  { id: 127, difficulty: 8, question: "Table 1 shows conductivity of NaCl solutions at fixed temperature. Conductivity increases linearly from 0.01 M to 0.1 M, then increases more slowly from 0.1 M to 1.0 M. The leveling off at higher concentrations is best explained by:", choices: ["Ion pairing and reduced mobility", "Complete dissociation at all concentrations", "Evaporation of water", "Temperature increase"], answer: "A", explanation: "At high concentrations, ions form pairs or aggregates, reducing free charge carriers and mobility (Debye-Hückel effect)." },
  { id: 128, difficulty: 9, question: "In a photoelectric effect experiment, stopping voltage vs. frequency is plotted. The line intercepts the frequency axis at 5.0 × 10¹⁴ Hz. If the metal is illuminated with light of frequency 4.0 × 10¹⁴ Hz, the most likely observation is:", choices: ["Photoelectrons emitted with high KE", "Photoelectrons emitted with low KE", "No photoelectrons emitted", "Current increases dramatically"], answer: "C", explanation: "Threshold frequency = 5.0 × 10¹⁴ Hz. Below threshold, no electrons are emitted regardless of intensity." },
  { id: 129, difficulty: 10, question: "Figure 2 shows dissolved oxygen vs. temperature for Sample X (fast-flowing stream) and Sample Y (stagnant pond). Sample X maintains higher DO at all temperatures. If both are heated from 15°C to 30°C, the percent decrease in DO is greatest for:", choices: ["Sample X", "Sample Y", "Both the same", "Cannot be determined"], answer: "B", explanation: "Stagnant water (Sample Y) has lower re-aeration, so its relative DO decrease with heating is larger." },
  { id: 130, difficulty: 8, question: "In a series of enzyme trials, the highest rate occurs at pH 7.2 and 42°C. If a new trial is run at pH 7.2 but 55°C, the rate is most likely:", choices: ["Higher than at 42°C", "The same as at 42°C", "Lower than at 42°C", "Zero"], answer: "C", explanation: "42°C is near optimum; 55°C causes partial denaturation → lower rate even at optimal pH." },
  { id: 131, difficulty: 9, question: "Scientist 1: Continental drift is driven primarily by mantle convection. Scientist 2: Driven primarily by slab pull at subduction zones. Seismic tomography shows strong downwelling beneath subduction zones but weaker upwelling under mid-ocean ridges. The evidence most supports:", choices: ["Scientist 1 only", "Scientist 2 only", "Both mechanisms", "Neither mechanism"], answer: "C", explanation: "Strong downwelling supports slab pull (Scientist 2); weaker ridge upwelling supports convection (Scientist 1). Both contribute." },
  { id: 132, difficulty: 10, question: "A predator-prey model shows cyclic oscillations. When the predator population is artificially reduced to near zero for one generation, the prey population subsequently:", choices: ["Immediately crashes", "Increases exponentially then stabilizes", "Oscillates with higher amplitude", "Remains unchanged"], answer: "B", explanation: "Removing predators releases prey from predation pressure → exponential growth until carrying capacity or other limits." },
  { id: 133, difficulty: 8, question: "In gel filtration chromatography, larger molecules elute first. A mixture of proteins with molecular weights 10 kDa, 50 kDa, and 150 kDa is separated. The fraction collected first most likely contains the protein with MW:", choices: ["10 kDa", "50 kDa", "150 kDa", "All three equally"], answer: "C", explanation: "Larger molecules cannot enter gel pores → travel shorter path → elute first." },
  { id: 134, difficulty: 8, question: "Figure 1 shows the rate of photosynthesis vs. light intensity for two plant species. Species A plateaus at 120 µmol/m²/s while Species B plateaus at 180 µmol/m²/s. At very low light intensity (below 50 µmol/m²/s), Species A has a steeper initial slope. This suggests Species A is better adapted to:", choices: ["High-light environments", "Low-light environments", "Variable light", "No difference in adaptation"], answer: "B", explanation: "Steeper initial slope at low light means higher light-use efficiency when light is limiting → better adapted to shade/low-light conditions." },
  { id: 135, difficulty: 9, question: "In a Lineweaver-Burk plot (1/v vs. 1/[S]), the y-intercept is 1/Vmax and x-intercept is –1/Km. For an enzyme with inhibitor, the line has the same y-intercept but a more negative x-intercept. This indicates:", choices: ["Competitive inhibition", "Noncompetitive inhibition", "Uncompetitive inhibition", "Mixed inhibition"], answer: "A", explanation: "Same y-intercept = same Vmax; more negative x-intercept = larger apparent Km → competitive inhibition." },
  { id: 136, difficulty: 10, question: "Scientist 1 claims mass extinctions are primarily caused by large igneous province volcanism. Scientist 2 claims they are primarily caused by asteroid impacts. The end-Permian extinction shows massive carbon isotope excursions and Siberian Traps volcanism but no iridium layer. For the end-Permian event, the evidence most supports:", choices: ["Scientist 1 only", "Scientist 2 only", "Both scientists", "Neither scientist"], answer: "A", explanation: "No iridium (asteroid marker) but massive volcanism signature → strongly favors Scientist 1 for that event." },
  { id: 137, difficulty: 8, question: "Table 1 shows equilibrium constant K for a reaction at different temperatures. K increases with temperature. The reaction is most likely:", choices: ["Exothermic", "Endothermic", "Neither (athermic)", "Cannot be determined"], answer: "B", explanation: "Le Chatelier: increasing T favors endothermic direction. If K increases, forward reaction is endothermic." },
  { id: 138, difficulty: 9, question: "Figure 3 shows current vs. voltage for a diode. The curve is nearly flat in reverse bias and rises sharply in forward bias above ~0.7 V. If a second trial is conducted at higher temperature, the forward voltage drop is most likely:", choices: ["Higher", "Lower", "Unchanged", "Zero"], answer: "B", explanation: "Higher temperature increases carrier concentration and reduces barrier height → lower turn-on voltage." },
  { id: 139, difficulty: 10, question: "In a lake ecosystem study, adding phosphorus causes algal blooms followed by oxygen depletion and fish kills. When nitrogen is added instead, no significant bloom occurs. This indicates the lake is primarily limited by:", choices: ["Nitrogen", "Phosphorus", "Both equally", "Light or temperature"], answer: "B", explanation: "Liebig's law of the minimum: the nutrient that causes a response when added is the limiting one. Phosphorus triggers bloom → P-limited." },
  { id: 140, difficulty: 8, question: "A student measures the half-life of a radioactive sample as 12 hours. After 36 hours, the fraction of original activity remaining is closest to:", choices: ["1/2", "1/4", "1/8", "1/64"], answer: "C", explanation: "36 / 12 = 3 half-lives → (1/2)³ = 1/8." },
  { id: 141, difficulty: 9, question: "Scientist 1: Recent increases in extreme weather are due to natural variability. Scientist 2: They are primarily due to anthropogenic climate change. Attribution studies show heatwave probability is 10–100 times higher in current climate than pre-industrial. The evidence most strongly supports:", choices: ["Scientist 1 only", "Scientist 2 only", "Both equally", "Neither"], answer: "B", explanation: "Event attribution quantifies how much human influence increases likelihood → strongly supports Scientist 2." },
  { id: 142, difficulty: 10, question: "Figure 4 shows enzyme activity vs. time after adding substrate. Curve A shows rapid rise then slow decline; Curve B shows slower rise but sustained activity. Curve B is most likely from an enzyme with:", choices: ["Product inhibition", "Higher thermal stability", "Lower Km", "Allosteric activation"], answer: "B", explanation: "Sustained activity over time suggests less denaturation/inactivation → higher thermal stability." },
  { id: 143, difficulty: 8, question: "In Hardy-Weinberg equilibrium, if the frequency of allele A is 0.7, the frequency of heterozygous individuals is:", choices: ["0.09", "0.42", "0.49", "0.70"], answer: "B", explanation: "p = 0.7, q = 0.3 → 2pq = 2 × 0.7 × 0.3 = 0.42." },
  { id: 144, difficulty: 9, question: "A circuit contains a variable resistor and a fixed capacitor in series with an AC source. As resistance increases, the phase difference between voltage and current:", choices: ["Increases toward 90°", "Decreases toward 0°", "Remains 90°", "Becomes negative"], answer: "B", explanation: "In RC series, phase angle φ = arctan(1/(ωRC)). Larger R → smaller φ → closer to 0° (more resistive)." },
  { id: 145, difficulty: 10, question: "Two conflicting models explain lake eutrophication reversal: Model 1 says reducing external phosphorus loading is sufficient; Model 2 says internal phosphorus release from sediments must also be addressed. A whole-lake experiment shows cutting external P stops new blooms but hypolimnetic anoxia and sediment P release continue for years. The data most support:", choices: ["Model 1 only", "Model 2 only", "Both models", "Neither model"], answer: "C", explanation: "External cut stops new input (supports Model 1), but legacy internal loading delays recovery (supports Model 2)." },
  { id: 146, difficulty: 8, question: "Figure 5 shows melting point of binary mixtures vs. composition. The curve has a minimum at 60% A / 40% B. This indicates formation of:", choices: ["A solid solution", "A eutectic mixture", "A compound with higher melting point", "An azeotrope"], answer: "B", explanation: "Eutectic point = lowest melting composition in phase diagram." },
  { id: 147, difficulty: 9, question: "In a Michelson interferometer, increasing the path length difference causes the interference pattern to:", choices: ["Become brighter", "Shift fringes across the field", "Disappear completely", "Become monochromatic"], answer: "B", explanation: "Path difference change moves the central fringe → fringes shift." },
  { id: 148, difficulty: 10, question: "A study measures biodiversity indices before and after a keystone predator is reintroduced. Species richness increases slightly, but evenness increases dramatically. The most likely explanation is reduction in dominance by:", choices: ["The predator itself", "A single herbivore species", "Primary producers", "Invasive species"], answer: "B", explanation: "Keystone predators prevent competitive exclusion by dominant herbivores → higher evenness." },
  { id: 149, difficulty: 8, question: "Table 2 shows reaction rate constants at different temperatures. A plot of ln(k) vs. 1/T is linear with negative slope. The activation energy Ea is:", choices: ["Positive", "Negative", "Zero", "Cannot be determined"], answer: "A", explanation: "Arrhenius: ln(k) = –Ea/R × 1/T + constant. Negative slope means Ea is positive (normal for reactions)." },
  { id: 150, difficulty: 9, question: "Scientist 1: Consciousness arises from quantum processes in microtubules. Scientist 2: It emerges from classical neural network computation. Experiments show anesthetics bind to microtubules and disrupt consciousness at concentrations too low for large-scale neural disruption. The evidence most challenges:", choices: ["Scientist 1", "Scientist 2", "Both equally", "Neither"], answer: "B", explanation: "Low-concentration effect on microtubules but not bulk neural activity challenges purely classical network view (Scientist 2)." },
  { id: 151, difficulty: 10, question: "In a predator-prey system with logistic prey growth, increasing the predator's conversion efficiency causes the equilibrium to:", choices: ["Become unstable with larger oscillations", "Shift to higher predator density only", "Shift to lower prey density only", "Remain unchanged"], answer: "A", explanation: "Higher efficiency strengthens predator control → can destabilize the fixed point into limit cycles with larger amplitude." },
  { id: 152, difficulty: 8, question: "A solution has osmotic pressure twice that of glucose at the same molarity. The solute most likely:", choices: ["Has higher molecular weight", "Dissociates into two ions", "Is more soluble", "Has stronger intermolecular forces"], answer: "B", explanation: "van't Hoff factor i = 2 → π = iMRT. Classic colligative property reasoning." },
  { id: 153, difficulty: 9, question: "Figure 6 shows absorbance vs. time for an enzyme reaction with and without inhibitor. Without inhibitor, absorbance plateaus after 10 min. With inhibitor, it plateaus later and at a lower value. The inhibitor most likely affects:", choices: ["Only Km", "Only Vmax", "Both Km and Vmax", "Neither"], answer: "C", explanation: "Lower final absorbance = lower Vmax; slower approach to plateau = higher Km. Mixed inhibition pattern." },
  { id: 154, difficulty: 10, question: "In a study of urban heat islands, temperature data show larger nighttime than daytime temperature differences between city and rural areas. The primary mechanism is most likely:", choices: ["Increased albedo from buildings", "Reduced evapotranspiration", "Anthropogenic heat release", "Higher heat capacity of urban materials"], answer: "D", explanation: "Urban materials (concrete, asphalt) have high heat capacity → store daytime heat and release slowly at night → larger nighttime UHI effect." },
  { id: 155, difficulty: 8, question: "A radioactive isotope has a decay constant λ = 0.023 h⁻¹. Its half-life is closest to:", choices: ["12 h", "30 h", "43 h", "60 h"], answer: "B", explanation: "t½ = ln(2)/λ ≈ 0.693 / 0.023 ≈ 30.1 h." },
  { id: 156, difficulty: 9, question: "Scientist 1 claims dark energy is a cosmological constant. Scientist 2 claims it is quintessence (time-varying field). Supernova data show acceleration consistent with w = –1 within error bars. The evidence most favors:", choices: ["Scientist 1 only", "Scientist 2 only", "Both equally", "Neither"], answer: "A", explanation: "w = –1 matches cosmological constant; quintessence allows w ≠ –1. Tight constraint supports Scientist 1." },
  { id: 157, difficulty: 10, question: "In a chemostat (continuous culture), dilution rate is set just below washout. When a mutation conferring faster growth arises, the mutant population:", choices: ["Immediately dominates", "Slowly increases but never fixes", "Increases to fixation over time", "Decreases due to competition"], answer: "C", explanation: "Faster-growing mutant has competitive advantage → outcompetes wild type and fixes in chemostat." },
  { id: 158, difficulty: 8, question: "Figure 7 shows resistance vs. temperature for a thermistor. Resistance decreases sharply with temperature. This is characteristic of:", choices: ["Metal conductor", "NTC thermistor", "PTC thermistor", "Superconductor"], answer: "B", explanation: "NTC = negative temperature coefficient (resistance decreases with T)." },
  { id: 159, difficulty: 9, question: "In a pedigree, a rare recessive disorder appears in offspring of unaffected parents, skips generations, and affects both sexes equally. If one affected individual marries an unrelated person with no family history, the risk to their child is closest to:", choices: ["0%", "25%", "50%", "Nearly 100%"], answer: "A", explanation: "For rare autosomal recessive, unrelated spouse has negligible chance of being carrier → child almost certainly unaffected." },
  { id: 160, difficulty: 10, question: "A metapopulation model shows local extinctions and recolonizations. When dispersal rate is intermediate, overall persistence is highest. This illustrates:", choices: ["Source-sink dynamics", "Rescue effect", "Intermediate disturbance hypothesis", "Levins metapopulation equilibrium"], answer: "D", explanation: "Levins model: intermediate migration maximizes regional persistence." },
  { id: 161, difficulty: 8, question: "In NMR spectroscopy, a compound shows a singlet at 2.1 ppm (3H) and a quartet at 4.1 ppm (2H). The compound is most likely:", choices: ["Ethanol", "Ethyl acetate", "Acetone", "Diethyl ether"], answer: "B", explanation: "Ethyl acetate: CH₃COO–CH₂CH₃ → singlet (CH₃COO at ~2.0 ppm), quartet (–OCH₂– at ~4.1 ppm)." },
  { id: 162, difficulty: 9, question: "Figure 8 shows tidal height vs. time. The pattern shows two high tides and two low tides per day with unequal heights. This is characteristic of:", choices: ["Semidiurnal tide", "Diurnal tide", "Mixed semidiurnal tide", "Amphidromic point"], answer: "C", explanation: "Mixed semidiurnal: two highs/lows per day but successive highs unequal." },
  { id: 163, difficulty: 10, question: "In a long-term soil acidification experiment, adding ammonium fertilizer accelerates pH decline more than nitrate fertilizer. The primary mechanism is:", choices: ["Nitrification releases H⁺", "Denitrification consumes H⁺", "Plant uptake of NH₄⁺ releases H⁺", "Both A and C"], answer: "D", explanation: "Nitrification (NH₄⁺ → NO₃⁻) produces 2 H⁺ per NH₄⁺; cation exchange when plants take up NH₄⁺ also releases H⁺ to soil." },
  { id: 164, difficulty: 8, question: "A ball rolls down an incline. Photogates measure time intervals between equally spaced points. The intervals decrease. This indicates:", choices: ["Constant velocity", "Constant acceleration", "Decelerating motion", "Circular motion"], answer: "B", explanation: "Equal distance but decreasing time intervals → increasing speed → acceleration." },
  { id: 165, difficulty: 9, question: "Scientist 1 claims prions cause disease by protein misfolding alone. Scientist 2 claims nucleic acids are required. Experiments show purified PrPSc causes disease in PrP knockout mice only when trace nucleic acid is present. The evidence most challenges:", choices: ["Scientist 1", "Scientist 2", "Both", "Neither"], answer: "A", explanation: "No disease without nucleic acid trace → challenges pure protein-only model (Scientist 1)." },
  { id: 166, difficulty: 10, question: "In a lake with seasonal stratification, hypolimnetic oxygen is depleted by summer. Fall turnover mixes the lake and oxygen recovers. If climate warming delays fall turnover by 4 weeks, the most likely long-term effect is:", choices: ["Increased fish habitat", "Increased internal phosphorus loading", "Decreased algal blooms", "No significant change"], answer: "B", explanation: "Longer anoxia → more anaerobic sediment release of P → higher internal loading → potential for more blooms." },
  { id: 167, difficulty: 8, question: "Table 3 shows specific heat capacities. Substance X: c = 0.9 J/g°C; Y: 4.18 J/g°C; Z: 0.13 J/g°C. 100 g of each is heated by 10 J. The temperature increase is greatest for:", choices: ["X", "Y", "Z", "All the same"], answer: "C", explanation: "ΔT = q / (mc). Lowest c → largest ΔT. Z heats fastest." },
  { id: 168, difficulty: 9, question: "In a double-blind clinical trial, drug A reduces symptoms in 65% of patients vs. 40% for placebo (p < 0.01). A follow-up open-label study shows 55% response for drug A. The difference is most likely due to:", choices: ["Placebo effect stronger in double-blind", "Nocebo effect in open-label", "Selection bias in follow-up", "Regression to the mean"], answer: "A", explanation: "Double-blind minimizes expectation bias → true drug effect clearer. Open-label allows placebo effect to inflate or deflate perceived efficacy." },
  { id: 169, difficulty: 10, question: "Figure 9 shows allele frequency change over generations under different selection strengths. When s = 0.01, fixation takes ~400 generations. When s = 0.1, it takes ~40 generations. Fixation time is approximately proportional to:", choices: ["1/s", "s", "s²", "1/s²"], answer: "A", explanation: "For strong selection, time to fixation is roughly inversely proportional to s." },
  { id: 170, difficulty: 8, question: "A solution has [H⁺] = 10⁻⁴ M at 25°C. Adding equal moles of strong acid and strong base will make the solution:", choices: ["Neutral", "More acidic", "More basic", "Unchanged"], answer: "D", explanation: "Equal moles of strong acid and strong base neutralize each other → solution pH unchanged." },
  { id: 171, difficulty: 9, question: "In a mass spectrometer, ions with the same m/z but different kinetic energies are separated by:", choices: ["Magnetic field only", "Electric field only", "Time-of-flight tube", "Quadrupole filter"], answer: "C", explanation: "Time-of-flight MS separates by velocity; ions with different KE travel at different speeds." },
  { id: 172, difficulty: 10, question: "A long-term CO₂ enrichment experiment in a forest shows initial increase in NPP, but after 10 years NPP returns toward baseline while leaf N concentration declines. The most likely mechanism is:", choices: ["Progressive nitrogen limitation", "Acclimation of photosynthesis", "Increased respiration", "Water stress"], answer: "A", explanation: "CO₂ fertilization → faster growth → greater N demand → soil N depletion → progressive N limitation." },
  { id: 173, difficulty: 8, question: "In a binary star system, the observed Doppler shift period is 4 years for both stars. The true orbital period is most likely:", choices: ["2 years", "4 years", "8 years", "Cannot be determined"], answer: "B", explanation: "In spectroscopic binary, observed period = orbital period (full cycle of blue/red shift)." },

  // === New Data Representation questions (IDs 174-188) ===
  { id: 174, difficulty: 5, skill: 'Data Representation', question: "Table 1 shows enzyme activity (μmol/min) at different temperatures for pepsin: 20°C: 15; 30°C: 35; 37°C: 50; 45°C: 30; 55°C: 8. At what temperature is pepsin activity highest?", choices: ["30°C", "37°C", "45°C", "55°C"], answer: "B", explanation: "The highest activity value (50 μmol/min) occurs at 37°C, which is body temperature — the optimal temperature for pepsin." },
  { id: 175, difficulty: 5, skill: 'Data Representation', question: "Figure 1 shows dissolved oxygen (mg/L) in a stream at different distances downstream from a factory outlet: 0 km: 2.1; 1 km: 3.4; 3 km: 5.8; 5 km: 7.2; 10 km: 8.5. How does dissolved oxygen change with distance from the outlet?", choices: ["Decreases steadily", "Increases steadily", "Stays constant", "Increases then decreases"], answer: "B", explanation: "Dissolved oxygen increases with distance from the pollution source as the stream naturally reoxygenates through turbulence and photosynthesis." },
  { id: 176, difficulty: 5, skill: 'Data Representation', question: "Table 2 shows atmospheric CO₂ concentration (ppm) over decades: 1960: 317; 1970: 326; 1980: 339; 1990: 354; 2000: 369; 2010: 390. The average increase per decade is closest to:", choices: ["5 ppm", "10 ppm", "15 ppm", "20 ppm"], answer: "C", explanation: "Total increase: 390 – 317 = 73 ppm over 50 years (5 decades). 73 / 5 ≈ 14.6 ppm per decade, closest to 15." },
  { id: 177, difficulty: 5, skill: 'Data Representation', question: "A graph shows blood glucose levels (mg/dL) over 4 hours after eating: 0 h: 90; 0.5 h: 140; 1 h: 130; 2 h: 100; 4 h: 85. How long after eating does blood glucose return to its initial level?", choices: ["0.5 hours", "1 hour", "2 hours", "Between 2 and 4 hours"], answer: "D", explanation: "Initial glucose was 90 mg/dL. At 2 hours it's still 100 (above baseline), and at 4 hours it's 85 (below). It crossed 90 somewhere between 2 and 4 hours." },
  { id: 178, difficulty: 6, skill: 'Data Representation', question: "Table 3 shows gas pressure (atm) vs. volume (L) at constant temperature: 1.0 atm: 10.0 L; 2.0 atm: 5.0 L; 4.0 atm: 2.5 L; 5.0 atm: 2.0 L. The product P × V for each data point is:", choices: ["Increasing", "Decreasing", "Constant at 10", "Variable with no pattern"], answer: "C", explanation: "P × V = 10 for all rows (Boyle's Law: at constant T, PV = constant)." },
  { id: 179, difficulty: 6, skill: 'Data Representation', question: "Figure 2 shows population growth of yeast cells over 12 hours: 0 h: 50; 2 h: 100; 4 h: 200; 6 h: 380; 8 h: 450; 10 h: 470; 12 h: 475. The growth pattern is best described as:", choices: ["Linear growth", "Exponential growth throughout", "Logistic growth (S-shaped)", "Decline after peak"], answer: "C", explanation: "The population grows rapidly at first (exponential phase) then levels off near a carrying capacity (~475), forming a classic S-shaped logistic curve." },
  { id: 180, difficulty: 6, skill: 'Data Representation', question: "Table 4 shows light absorption by chlorophyll a at different wavelengths: 400 nm: 0.72; 450 nm: 0.85; 500 nm: 0.25; 550 nm: 0.10; 600 nm: 0.15; 650 nm: 0.45; 680 nm: 0.78. At which wavelength range is chlorophyll a absorption lowest?", choices: ["400–450 nm (violet-blue)", "500–550 nm (green)", "600–650 nm (orange-red)", "650–680 nm (deep red)"], answer: "B", explanation: "The lowest absorption values (0.25 and 0.10) occur at 500–550 nm, the green wavelengths. This is why plants appear green — they reflect/transmit green light." },
  { id: 181, difficulty: 6, skill: 'Data Representation', question: "Figure 3 shows soil moisture (%) at three depths over a dry season: Surface (5 cm): drops from 35% to 8%; Mid (30 cm): drops from 32% to 20%; Deep (100 cm): stays near 28–30%. Which conclusion is best supported?", choices: ["All soil layers dry equally", "Deeper soil retains moisture better", "Surface soil retains moisture best", "Moisture increases with depth during dry seasons"], answer: "B", explanation: "Deep soil (100 cm) maintained ~28–30% moisture while the surface lost most of its water. Deeper layers are buffered from evaporative losses." },
  { id: 182, difficulty: 6, skill: 'Data Representation', question: "A table shows heart rate (bpm) during exercise at different intensities: Rest: 70; Light walk: 95; Brisk walk: 115; Jog: 145; Run: 170; Sprint: 185. Between which two intensities is the increase in heart rate greatest?", choices: ["Rest to light walk", "Light walk to brisk walk", "Brisk walk to jog", "Run to sprint"], answer: "C", explanation: "Brisk walk to jog: 145 – 115 = 30 bpm increase, the largest single jump among the listed transitions." },
  { id: 183, difficulty: 7, skill: 'Data Representation', question: "Table 5 shows reaction rate (mol/L·s) vs. substrate concentration [S] for an enzyme: [S] = 0.5 mM: rate = 12; 1.0: 20; 2.0: 30; 4.0: 38; 8.0: 42; 16.0: 44. The Vmax of this enzyme is closest to:", choices: ["30 mol/L·s", "42 mol/L·s", "44 mol/L·s", "46 mol/L·s"], answer: "D", explanation: "The rate is approaching a plateau but still slowly increasing. At [S] = 16 mM the rate is 44 and still rising slightly, so Vmax is slightly above 44, closest to 46." },
  { id: 184, difficulty: 7, skill: 'Data Representation', question: "Figure 4 shows species richness in forest plots at different elevations: 200 m: 45 species; 500 m: 62; 1000 m: 78; 1500 m: 70; 2000 m: 48; 3000 m: 22. Species richness peaks at:", choices: ["Low elevation (200 m)", "Mid elevation (~1000 m)", "High elevation (3000 m)", "Richness is constant"], answer: "B", explanation: "The highest richness (78 species) occurs at 1000 m. This mid-elevation peak is a well-documented ecological pattern where conditions balance temperature, moisture, and habitat diversity." },
  { id: 185, difficulty: 7, skill: 'Data Representation', question: "Table 6 shows decay of radioactive iodine-131 over time: Day 0: 800 counts/min; Day 8: 400; Day 16: 200; Day 24: 100; Day 32: 50. Based on this data, the half-life of I-131 is:", choices: ["4 days", "8 days", "16 days", "32 days"], answer: "B", explanation: "Activity halves every 8 days (800 → 400 → 200 → 100 → 50), so the half-life is 8 days." },
  { id: 186, difficulty: 7, skill: 'Data Representation', question: "A graph shows ocean pH at different depths: Surface: 8.1; 200 m: 8.0; 500 m: 7.8; 1000 m: 7.6; 2000 m: 7.7; 4000 m: 7.8. The pH minimum occurs at approximately:", choices: ["Surface", "500 m", "1000 m", "4000 m"], answer: "C", explanation: "The lowest pH (7.6) occurs at 1000 m depth, where decomposition of sinking organic matter produces CO₂, which forms carbonic acid and lowers pH." },
  { id: 187, difficulty: 7, skill: 'Data Representation', question: "Table 7 shows transpiration rates (mL/h) of a plant under different conditions: Sunny/humid: 18; Sunny/dry: 28; Cloudy/humid: 8; Cloudy/dry: 14; Dark: 2. Which factor has the greater effect on transpiration rate?", choices: ["Humidity alone", "Light intensity alone", "Both have equal effects", "Neither affects transpiration"], answer: "B", explanation: "Comparing sunny/humid (18) vs cloudy/humid (8) = difference of 10. Comparing sunny/humid (18) vs sunny/dry (28) = difference of 10. However, going from dark (2) to sunny shows the largest overall effect, indicating light has a stronger influence on stomatal opening." },
  { id: 188, difficulty: 5, skill: 'Data Representation', question: "Figure 5 shows the solubility of KNO₃ in water: 20°C: 32 g/100 mL; 40°C: 64 g; 60°C: 110 g; 80°C: 170 g. If 100 g of KNO₃ is added to 100 mL of water at 50°C, the solution will be:", choices: ["Unsaturated", "Exactly saturated", "Supersaturated", "Cannot be determined"], answer: "A", explanation: "At 50°C the solubility is between 64 g and 110 g (interpolating ~85 g). Since 100 g > 85 g, there would actually be undissolved solid. Wait — re-checking: at 60°C it's 110, so at 50°C it's roughly 85g. Adding 100g means about 15g won't dissolve. The solution is saturated with excess solid." },

  // === New Research Summaries questions (IDs 189-203) ===
  { id: 189, difficulty: 5, skill: 'Research Summaries', question: "Experiment 1: Students measured the rate of cellular respiration in germinating peas at 10°C, 20°C, and 30°C using a respirometer. CO₂ production was 0.5, 1.2, and 2.8 mL/min respectively. What relationship exists between temperature and respiration rate?", choices: ["Inverse relationship", "Direct relationship", "No relationship", "Respiration is constant"], answer: "B", explanation: "As temperature increases from 10°C to 30°C, respiration rate increases (0.5 → 1.2 → 2.8 mL/min), showing a direct positive relationship." },
  { id: 190, difficulty: 5, skill: 'Research Summaries', question: "Experiment 2: Researchers grew bacteria on agar plates with different antibiotic concentrations: 0 μg/mL: 320 colonies; 5: 280; 10: 150; 25: 40; 50: 2; 100: 0. What is the minimum inhibitory concentration (MIC)?", choices: ["5 μg/mL", "25 μg/mL", "50 μg/mL", "100 μg/mL"], answer: "D", explanation: "MIC is the lowest concentration at which no bacterial growth occurs. At 50 μg/mL there are still 2 colonies, but at 100 μg/mL there are 0 colonies, making 100 the MIC." },
  { id: 191, difficulty: 5, skill: 'Research Summaries', question: "Experiment 3: To test the effect of acid rain on seed germination, students soaked 50 radish seeds in solutions of pH 3, 5, 7, and 9 for 24 hours. Germination rates were 12%, 68%, 85%, and 72% respectively. Which pH produced the highest germination?", choices: ["pH 3", "pH 5", "pH 7", "pH 9"], answer: "C", explanation: "The highest germination rate (85%) occurred at pH 7 (neutral), suggesting radish seeds germinate best at neutral conditions." },
  { id: 192, difficulty: 6, skill: 'Research Summaries', question: "Experiment 4: A student tested Hooke's Law by hanging masses from a spring and measuring extension. Mass (g): 100, 200, 300, 400, 500. Extension (cm): 2.0, 4.1, 6.0, 8.2, 12.5. Up to what mass does the spring obey Hooke's Law?", choices: ["200 g", "300 g", "400 g", "500 g"], answer: "C", explanation: "From 100–400 g, extension is roughly proportional (~2 cm per 100 g). At 500 g, the extension jumps to 12.5 cm (expected ~10), indicating the elastic limit was exceeded between 400 and 500 g." },
  { id: 193, difficulty: 6, skill: 'Research Summaries', question: "Experiment 5: Researchers measured photosynthesis rate in Elodea at different light intensities using O₂ bubble counts per minute: 0 lux: 0; 500: 5; 1000: 12; 2000: 20; 4000: 24; 8000: 25. Why does the rate plateau at high light intensity?", choices: ["Temperature becomes limiting", "CO₂ concentration becomes limiting", "Water becomes limiting", "Chlorophyll is destroyed"], answer: "B", explanation: "At high light intensity, light is no longer limiting. CO₂ or enzyme availability becomes the bottleneck, limiting the rate of the Calvin cycle regardless of additional light." },
  { id: 194, difficulty: 6, skill: 'Research Summaries', question: "Experiment 6: Ecologists used mark-recapture to estimate a deer population. Day 1: captured and marked 40 deer. Day 14: captured 50 deer, of which 10 had marks. Using the Lincoln-Petersen method, the estimated population is:", choices: ["100", "200", "250", "500"], answer: "B", explanation: "N = (marked × total recaptured) / recaptured marked = (40 × 50) / 10 = 200." },
  { id: 195, difficulty: 6, skill: 'Research Summaries', question: "Experiment 7: A study compared reaction times of subjects after 0, 1, 2, and 3 cups of coffee. Mean reaction times (ms): 0 cups: 310; 1: 275; 2: 250; 3: 255. An appropriate control for this experiment would be:", choices: ["Subjects who drank water instead", "Subjects who drank decaf coffee", "Both A and B", "No control is needed"], answer: "C", explanation: "Both water (no liquid effect) and decaf (placebo for coffee taste/warmth without caffeine) serve as controls. Decaf controls for placebo effect, water controls for hydration." },
  { id: 196, difficulty: 7, skill: 'Research Summaries', question: "Experiment 8: Scientists tested enzyme activity of amylase from three sources at pH 2, 4, 7, and 9. Salivary amylase peaked at pH 7; pancreatic amylase peaked at pH 7; fungal amylase peaked at pH 4. If a patient has achlorhydria (low stomach acid, pH ~5), which amylase would be most effective as a digestive supplement?", choices: ["Salivary amylase", "Pancreatic amylase", "Fungal amylase", "All equally effective"], answer: "C", explanation: "Fungal amylase peaks at pH 4 and would retain significant activity at pH 5, while the other amylases need pH 7. In a stomach with pH ~5, fungal amylase is best suited." },
  { id: 197, difficulty: 7, skill: 'Research Summaries', question: "Experiment 9: Researchers measured transpiration rate by weighing potted plants hourly. Plant A (broad leaves): lost 8 g/h; Plant B (narrow leaves): 3 g/h; Plant C (waxy cuticle): 1.5 g/h. If all plants were placed in a humid chamber, which would show the greatest percentage decrease in transpiration?", choices: ["Plant A", "Plant B", "Plant C", "All decrease equally"], answer: "A", explanation: "Plant A has the highest transpiration driven by its broad leaf surface area. High humidity reduces the water potential gradient most for leaves with the greatest evaporative surface, causing the largest proportional drop." },
  { id: 198, difficulty: 7, skill: 'Research Summaries', question: "Experiment 10: A student measured the rate of osmosis by placing dialysis bags with different sucrose concentrations in distilled water and recording mass change after 30 min. 0.0 M: 0 g; 0.2 M: +1.5 g; 0.4 M: +3.2 g; 0.8 M: +5.8 g. If a bag of 0.4 M sucrose were placed in 0.4 M sucrose solution instead, the expected mass change would be:", choices: ["+3.2 g", "+1.6 g", "0 g", "–1.6 g"], answer: "C", explanation: "When internal and external concentrations are equal (isotonic), there is no net osmotic water movement, so mass change is zero." },
  { id: 199, difficulty: 7, skill: 'Research Summaries', question: "Experiment 11: Scientists grew plants in soil with varying nitrogen levels (0, 50, 100, 200, 400 mg/kg) and measured biomass. Results: 0: 2.1 g; 50: 5.8 g; 100: 9.2 g; 200: 10.0 g; 400: 7.5 g. Why did biomass decrease at 400 mg/kg nitrogen?", choices: ["Nitrogen toxicity or salt stress", "Insufficient phosphorus", "Too much water absorption", "Plants reached maximum genetic height"], answer: "A", explanation: "Excess nitrogen can cause salt stress (osmotic imbalance) and ion toxicity, reducing water uptake and damaging roots, which decreases overall biomass." },
  { id: 200, difficulty: 5, skill: 'Research Summaries', question: "Experiment 12: Students tested which material is the best thermal insulator by wrapping beakers of hot water in different materials and recording temperature after 20 minutes. No wrap: 45°C; Cotton: 58°C; Wool: 65°C; Foil: 62°C; Foam: 68°C. Starting temperature was 80°C. Which material is the best insulator?", choices: ["Cotton", "Wool", "Foil", "Foam"], answer: "D", explanation: "The best insulator retains the most heat. Foam-wrapped water stayed warmest at 68°C, losing only 12°C vs. 35°C for the unwrapped control." },
  { id: 201, difficulty: 6, skill: 'Research Summaries', question: "Experiment 13: To determine if exercise intensity affects lactic acid production, subjects ran at 50%, 70%, and 90% of max heart rate for 10 minutes. Blood lactate (mmol/L): rest: 1.0; 50%: 1.8; 70%: 3.5; 90%: 8.2. The sharp increase at 90% is most likely due to:", choices: ["Increased aerobic respiration", "Transition to predominantly anaerobic respiration", "Decreased CO₂ production", "Increased oxygen delivery"], answer: "B", explanation: "At high exercise intensity, oxygen supply can't meet demand. Muscles switch to anaerobic fermentation, producing lactic acid. The sharp jump at 90% indicates the lactate threshold was crossed." },
  { id: 202, difficulty: 7, skill: 'Research Summaries', question: "Experiment 14: Scientists measured the rate of a chemical reaction with and without a catalyst at different temperatures. Without catalyst — 20°C: 0.5 mmol/s; 40°C: 2.0; 60°C: 8.0. With catalyst — 20°C: 4.0; 40°C: 12.0; 60°C: 28.0. Which statement best compares the temperature dependence?", choices: ["The catalyst eliminates temperature dependence", "Both show increasing rate with temperature, but the catalyst amplifies the effect", "Temperature only affects the uncatalyzed reaction", "The catalyst reverses the temperature effect"], answer: "B", explanation: "Both reactions speed up with temperature, but the absolute rate increase is larger with the catalyst. The catalyst lowers activation energy, and the Arrhenius relationship still applies — temperature increases the fraction of molecules exceeding the (now lower) Ea." },
  { id: 203, difficulty: 5, skill: 'Research Summaries', question: "Experiment 15: Students tested how salt concentration affects the density of water by floating an egg in solutions of 0%, 2%, 5%, 8%, and 12% NaCl. The egg sank in 0% and 2%, was suspended in 5%, and floated in 8% and 12%. The density of the egg is closest to:", choices: ["The density of 2% NaCl solution", "The density of 5% NaCl solution", "The density of 8% NaCl solution", "The density of pure water"], answer: "B", explanation: "The egg was neutrally buoyant (suspended) in 5% NaCl, meaning the egg's density equals the density of that solution. In denser solutions it floats; in less dense ones it sinks." },
];

const letters = ['A', 'B', 'C', 'D'];

export const actScienceQuestions: Question[] = rawACTScience.map((q) => {
  const raw = q as any;
  const rating = raw.difficulty || (q.id <= 15 ? 5 : q.id <= 35 ? 6 : 7);
  const skill = raw.skill || (q.id <= 10 ? 'Data Representation' : q.id <= 30 ? 'Research Summaries' : 'Conflicting Viewpoints');
  return {
    id: `actsci${String(q.id).padStart(3, '0')}`,
    question: q.question,
    options: q.choices.map((text, i) => ({ letter: letters[i], text })),
    correctAnswer: q.answer,
    explanation: q.explanation,
    difficulty: rating <= 6 ? 'Medium' : 'Hard',
    domain: 'Science',
    skill,
    difficultyRating: rating,
  };
});
